mapper.select:
/* ProdSaleDayStoreBensonMapper.getDivisionExcelDownloadUserIdChk */
SELECT COUNT(*)
FROM TB_HQ_NMCODE thn
WHERE 1=1
AND thn.HQ_OFFICE_CD = #{hqOfficeCd}
AND thn.NMCODE_GRP_CD = '168'
AND thn.NMCODE_NM = #{userId}

/* ProdSaleDayStoreBensonMapper.getDownloadSeq */
SELECT SQ_TB_CM_DOWNLOAD_LIMIT_CHECK.NEXTVAL AS SEQ
FROM dual

mapper.update:
/* ProdSaleDayStoreBensonMapper.getDivisionExcelDownloadSaveUpdate */
UPDATE
TB_CM_DOWNLOAD_LIMIT_CHECK
SET
DOWNLOAD_DT = #{modDt},
MOD_DT = #{modDt},
MOD_ID = #{modId}
WHERE 1=1
AND ORGN_CD = #{orgnCd}
AND SEQ = #{seq}
